package org.apache.commons.collections.list.steps;

import org.apache.commons.collections.list.TreeList;
import static org.junit.Assert.*;

import io.cucumber.java.en.*;

import java.util.List;
import java.util.ListIterator;

public class StepDefs {
    private List<String> treeList;
    private ListIterator<String> listIterator;

    @Given("a TreeList containing the strings {string}, {string}, {string}, {string}")
    public void a_TreeList_containing_the_strings(String string1, String string2, String string3, String string4) {
        treeList = new TreeList<String>();
        treeList.add(string1);
        treeList.add(string2);
        treeList.add(string3);
        treeList.add(string4);
    }

    @And("a ListIterator is positioned after {string}")
    public void a_ListIterator_is_positioned_after(String element) {
        listIterator = treeList.listIterator();

        // Move the iterator to after the specified element
        while (listIterator.hasNext()) {
            String current = listIterator.next();
            if (current.equals(element)) {
                break; // Now the iterator is positioned after the element
            }
        }
    }

    @When("I iterate previous to {string}")
    public void i_iterate_previous_to(String element) {
        String previousElement = listIterator.previous();
        assertEquals(element, previousElement);
    }

    @And("I remove the current element {string} via the iterator")
    public void i_remove_the_current_element_via_the_iterator(String element) {
        try {
            // The current element should be the one that was just previous'd to
            listIterator.remove();
        } catch (Exception e) {
            throw new RuntimeException("Error removing element: " + e.getMessage());
        }
    }

    @Then("the next call to previous\\(\\) on the iterator should return {string}")
    public void the_next_call_to_previous_on_the_iterator_should_return(String expectedElement) {
        try {
            String actualElement = listIterator.previous();
            assertEquals(expectedElement, actualElement);
        } catch (Exception e) {
            throw new RuntimeException("Error calling previous(): " + e.getMessage());
        }
    }
}

